mapper.select:
select rights_template_id as rightsTemplateId, rights_name as rightsName, rights_type as rightsType, quota_mode as quotaMode, quota_value as quotaValue, valid_days as validDays, writeoff_mode as writeoffMode, applicable_role as applicableRole, status, remark, create_time as createTime, update_time as updateTime from jst_rights_template
del_flag = '0'
and rights_name like concat('%', #{rightsName}, '%')
and rights_type = #{rightsType}
and status = #{status}
order by rights_template_id desc

mapper.update:
update jst_rights_template
set status = #{status},
    update_by = #{updateBy},
    update_time = #{updateTime}
where rights_template_id = #{rightsTemplateId}
  and del_flag = '0'

update jst_rights_template
set del_flag = '2',
    update_by = #{updateBy},
    update_time = #{updateTime}
where rights_template_id = #{rightsTemplateId}
  and del_flag = '0'
